function shuffledGateways(
    uint256 seed
) public view returns (string[] memory urls) {
    urls = provider.gateways();
    uint256 n = urls.length;
    for (uint256 i = 1; i < n; ++i) {
        uint256 j = seed % (i + 1);
        (urls[i], urls[j]) = (urls[j], urls[i]);
        assembly {
            mstore(0, seed)
            seed := keccak256(0, 32)
        }
    }
}

